1	export interface ItemSpec {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface Customer {
9	  yearsWithMHPCO: number;
10	}
11	
12	export interface QuoteInput {
13	  customer: Customer;
14	  items: ItemSpec[];
15	}
16	
17	export interface QuoteResult {
18	  premium: number;
19	}
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_RATE = 0.1;
23	const CURSE_SURCHARGE_RATE = 0.5;
24	const BLOCK_SIZE = 3;
25	const BLOCK_PRICE = 60;
26	const COMPONENT_TYPES = ["rune", "moonstone"];
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	function basePremiumFor(item: ItemSpec): number {
38	  return BASE_PREMIUMS[item.type] ?? 0;
39	}
40	
41	function sumBasePremiums(items: ItemSpec[]): number {
42	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
43	}
44	
45	function countItemsOfType(items: ItemSpec[], type: string): number {
46	  return items.filter((item) => item.type === type).length;
47	}
48	
49	function blockAdjustmentFor(items: ItemSpec[], componentType: string): number {
50	  const count = countItemsOfType(items, componentType);
51	  if (count !== BLOCK_SIZE) return 0;
52	  return BLOCK_PRICE - BLOCK_SIZE * BASE_PREMIUMS[componentType];
53	}
54	
55	function blockAdjustment(items: ItemSpec[]): number {
56	  return COMPONENT_TYPES.reduce(
57	    (sum, componentType) => sum + blockAdjustmentFor(items, componentType),
58	    0
59	  );
60	}
61	
62	function itemSurchargeFor(item: ItemSpec): number {
63	  return item.cursed ? basePremiumFor(item) * CURSE_SURCHARGE_RATE : 0;
64	}
65	
66	function sumItemSurcharges(items: ItemSpec[]): number {
67	  return items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
68	}
69	
70	export function quote(input: QuoteInput): QuoteResult {
71	  const items = input.items;
72	  const policyBasePremium = sumBasePremiums(items) + blockAdjustment(items);
73	  const itemSurcharges = sumItemSurcharges(items);
74	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
75	  return {
76	    premium: Math.ceil(
77	      policyBasePremium + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE
78	    ),
79	  };
80	}
81	
82	export function claim(): unknown {
83	  return undefined;
84	}
